const fs = require('fs');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const raw = $input.first().json;
const body = raw.body || raw;
const command = String(body.command || 'Atlas status');
const detail = String(body.detail || '');
const entities = ctx.entities || {};
const founder = ctx.founder || {};
const verticals = ctx.verticals || {};
const tech = ctx.technology || {};
const programs = (ctx.programs || []).filter(p => p.active);
const programSummary = programs.length > 0 ? programs.map(p => `${p.name}: ${p.status} — ${p.notes}`).join(' | ') : 'No active programs';
const revenue = ctx.revenue_targets || {};
const compliance = (ctx.compliance_rules || []).join('\n- ');
const verticalSummary = Object.entries(verticals).map(([k, v]) => {
  const regs = (v.key_regulations || []).slice(0, 3).join(', ');
  return `${k} — ${v.name} | Status: ${v.status} | Margin: ${v.margin || 'TBD'} | Regs: ${regs}`;
}).join('\n');
const companyContext = `KAI-NETICS CONTEXT\nFP: ${entities.FP?.name} | EIN: ${entities.FP?.ein}\nEAF: ${entities.EAF?.name} | EIN: ${entities.EAF?.ein}\nMONK: ${entities.MONK?.status}\nFounder: ${founder.name} | ${(founder.credentials||[]).join(', ')}\nVerticals:\n${verticalSummary}\nMONK: ${tech.MONK?.description}\nBVLOS: ${tech.MONK?.bvlos_relevance}\nSBIR: ${tech.MONK?.sbir_target}\nActive Programs: ${programSummary}\nRevenue: Y1 ${revenue.year1_total} Y2 ${revenue.year2_total} Y3 ${revenue.year3_total}\nCompliance:\n- ${compliance}\nNOTE: FAA Part 108 BVLOS final rule INCOMING — MONK is the compliance case.`;
const kott = `Dr. Alexander Kott — Technical Advisor. Former Chief Scientist U.S. Army Research Laboratory 20+ years. Validated MONK architecture. All claims must survive his review.`;
let systemPrompt = '', userPrompt = detail, outputFolder = 'Atlas_Outputs', outputPrefix = 'Atlas';
if (command === 'Atlas SBIR' || command === 'atlas sbir') {
  systemPrompt = `You are Atlas, Senior Technical Architect for KAI-Netics. Draft SBIR Phase I for DHS S&T/DoD. Technically credible, peer-review quality. Focus MONK + Part 108.\n${kott}\n${companyContext}`;
  outputFolder = 'SBIR'; outputPrefix = 'SBIR';
  if (!detail) userPrompt = 'Draft Problem Statement and Technical Innovation for DHS S&T SBIR Phase I. Focus: MONK mission governance for BVLOS. Incorporate Part 108 as market timing. Reference Dr. Kott ARL background.';
} else if (command === 'Atlas MONK' || command === 'atlas monk') {
  systemPrompt = `You are Atlas, Senior Technical Architect for KAI-Netics. Produce MONK architecture documentation. DoD standard. Precise.\n${kott}\n${companyContext}`;
  outputFolder = 'MONK'; outputPrefix = 'MONK';
} else if (command === 'Atlas BVLOS' || command === 'atlas bvlos') {
  systemPrompt = `You are Atlas, Senior Technical Architect for KAI-Netics. Produce FAA BVLOS waiver documentation. FAA AC quality. MONK is the core safety argument. Reference Part 108 and FAA-2022-1258.\n${kott}\n${companyContext}`;
  outputFolder = 'SBIR'; outputPrefix = 'BVLOS';
} else if (['Atlas V1','Atlas V2','Atlas V3','Atlas V4','Atlas V5','Atlas V6','Atlas V7'].includes(command)) {
  const vKey = command.split(' ')[1]; const v = verticals[vKey] || {};
  systemPrompt = `You are Atlas, Senior Technical Architect for KAI-Netics. Market analysis for ${vKey}: ${v.name}.\n${companyContext}`;
  outputFolder = 'Atlas_Outputs'; outputPrefix = `${vKey}_Analysis`;
  if (!detail) userPrompt = `Full market entry analysis for ${v.name}: DMV target customers, procurement pathway, compliance, pricing, fleet requirements, timeline, top 3 risks.`;
} else if (command === 'Atlas Kott prep' || command === 'atlas kott prep') {
  systemPrompt = `You are Atlas. Prepare Dr. Kott advisory briefing. Executive technical brief. Lead with decision needed. Max 500 words.\n${kott}\n${companyContext}`;
  outputFolder = 'Atlas_Outputs'; outputPrefix = 'Kott_Prep';
} else if (command === 'Atlas status' || command === 'Atlas Status' || command === 'atlas status' || command === 'Atlas') {
  const statusReport = `ATLAS v2 OPERATIONAL\nContext loaded: ${Object.keys(ctx).length} sections | Verticals: ${Object.keys(verticals).length}\nActive Programs: ${programSummary}\nCommands: Atlas SBIR | MONK | BVLOS | V1-V7 | Kott prep | status\nPart 108 BVLOS: FLAGGED — incorporated into SBIR/BVLOS outputs.`;
  return [{ json: { command, statusReport, isStatus: true, timestamp: new Date().toISOString() } }];
} else {
  systemPrompt = `You are Atlas, Senior Technical Architect for KAI-Netics. Answer technical architecture questions across all 7 verticals.\n${kott}\n${companyContext}`;
  if (!detail) userPrompt = command;
}
return [{ json: { command, userPrompt, systemPrompt, outputFolder, outputPrefix, isStatus: false, timestamp: new Date().toISOString() } }];

const fs = require('fs'), https = require('https');
const { systemPrompt, userPrompt, outputFolder, outputPrefix, command, timestamp } = $input.first().json;
const requestBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 4096, system: systemPrompt, messages: [{ role: 'user', content: userPrompt }] });
const options = { hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': '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', 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) } };
const result = await new Promise((resolve, reject) => {
  const req = https.request(options, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
