const https = require('https');
const input = $input.first().json;

const SUPABASE_URL = 'raxpmeltyxmtiihxoxpa.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InJheHBtZWx0eXhtdGlpaHhveHBhIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzY3ODI5MDIsImV4cCI6MjA5MjM1ODkwMn0.UScReg6BG4pimbjMeIE7NB2glcpdbgUbDLnDhDLURPM';

const record = {
  agent: 'Atlas',
  trigger_type: 'webhook',
  status: 'success',
  items_processed: 1,
  output_file_path: input.filename ? '/data/' + input.outputFolder + '/' + input.filename : null,
  workflow_version: 'v2',
  notes: input.command || 'Atlas run'
};

try {
  const body = JSON.stringify(record);
  const result = await new Promise(function(resolve, reject) {
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      path: '/rest/v1/agent_executions',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Prefer': 'return=minimal',
        'Content-Length': Buffer.byteLength(body)
      }
    }, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode }); });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  const out = Object.assign({}, input);
  out.supabaseLogged = result.status === 201 || result.status === 200;
  out.supabaseStatus = result.status;
  return [{ json: out }];
} catch(e) {
  const out = Object.assign({}, input);
  out.supabaseLogged = false;
  out.supabaseError = e.message;
  return [{ json: out }];
}
